snippets.C0646:
-- Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación | ID: C0646
-- Oracle PL/SQL: FUNCTION + PROCEDURE (módulo 11)

CREATE OR REPLACE FUNCTION validate_rut(p_rut IN VARCHAR2) RETURN NUMBER
IS
  v_clean VARCHAR2(32);
  v_body  VARCHAR2(32);
  v_dv    CHAR(1);
  v_sum   NUMBER := 0;
  v_mul   NUMBER := 2;
  v_i     NUMBER;
  v_d     NUMBER;
  v_mod   NUMBER;
  v_dvcalc CHAR(1);
BEGIN
  v_clean := UPPER(REPLACE(REPLACE(REPLACE(p_rut, '.', ''), '-', ''), ' ', ''));
  IF LENGTH(v_clean) < 2 THEN RETURN 0; END IF;

  v_body := SUBSTR(v_clean, 1, LENGTH(v_clean)-1);
  v_dv   := SUBSTR(v_clean, -1, 1);

  IF NOT REGEXP_LIKE(v_body, '^[0-9]+$') THEN RETURN 0; END IF;

  v_i := LENGTH(v_body);
  WHILE v_i > 0 LOOP
    v_d := TO_NUMBER(SUBSTR(v_body, v_i, 1));
    v_sum := v_sum + (v_d * v_mul);
    v_mul := CASE WHEN v_mul = 7 THEN 2 ELSE v_mul + 1 END;
    v_i := v_i - 1;
  END LOOP;

  v_mod := 11 - MOD(v_sum, 11);
  v_dvcalc := CASE WHEN v_mod = 11 THEN '0'
                   WHEN v_mod = 10 THEN 'K'
                   ELSE TO_CHAR(v_mod) END;

  RETURN CASE WHEN v_dv = v_dvcalc THEN 1 ELSE 0 END;
END;
/

CREATE OR REPLACE PROCEDURE sp_validate_rut(p_rut IN VARCHAR2, p_out OUT NUMBER)
IS
BEGIN
  p_out := validate_rut(p_rut);
END;
/

-- Demo
SELECT validate_rut('12.345.678-5') AS is_valid FROM dual;

